  1→import type {
  2→	ModelTokensTrendData,
  3→	OverviewKPIs,
  4→	UsageTrendData,
  5→} from "@rudel/api-routes";
  6→import {
  7→	buildDateFilter,
  8→	escapeString,
  9→	queryClickhouse,
 10→} from "../clickhouse.js";
 11→
 12→export interface Insight {
 13→	type: "trend" | "performer" | "alert" | "info";
 14→	severity: "positive" | "warning" | "negative" | "info";
 15→	message: string;
 16→	link: string;
 17→}
 18→
 19→/**
 20→ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
 21→ */
 22→export async function getOverviewKPIs(
 23→	orgId: string,
 24→	days = 7,
 25→): Promise<OverviewKPIs> {
 26→	const org = escapeString(orgId);
 27→	const dateFilter = buildDateFilter(days);
 28→
 29→	const query = `
 30→    SELECT
 31→      uniq(user_id) as distinct_users,
 32→      count() as distinct_sessions,
 33→      uniq(if(git_remote != '', git_remote, if(repository != '', repository, project_path))) as distinct_projects,
 34→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN subagent_types as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_subagents,
 35→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN skills as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_skills,
 36→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN slash_commands as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_slash_commands
 37→    FROM rudel.session_analytics
 38→    WHERE ${dateFilter}
 39→      AND organization_id = '${org}'
 40→  `;
 41→
 42→	const result = await queryClickhouse<OverviewKPIs>(query);
 43→	const row = result[0];
 44→	if (!row) {
 45→		return {
 46→			distinct_users: 0,
 47→			distinct_sessions: 0,
 48→			distinct_projects: 0,
 49→			distinct_subagents: 0,
 50→			distinct_skills: 0,
 51→			distinct_slash_commands: 0,
 52→		};
 53→	}
 54→	// ClickHouse returns UInt64 as strings when output_format_json_quote_64bit_integers is true (the default)
 55→	return {
 56→		distinct_users: Number(row.distinct_users),
 57→		distinct_sessions: Number(row.distinct_sessions),
 58→		distinct_projects: Number(row.distinct_projects),
 59→		distinct_subagents: Number(row.distinct_subagents),
 60→		distinct_skills: Number(row.distinct_skills),
 61→		distinct_slash_commands: Number(row.distinct_slash_commands),
 62→	};
 63→}
 64→
 65→/**
 66→ * Get token usage broken down by model and day
 67→ */
 68→export async function getModelTokensTrend(
 69→	orgId: string,
 70→	days = 30,
 71→): Promise<ModelTokensTrendData[]> {
 72→	const org = escapeString(orgId);
 73→	const dateFilter = buildDateFilter(days);
 74→
 75→	const query = `
 76→    SELECT
 77→      toDate(session_date) as date,
 78→      model_used as model,
 79→      sum(total_tokens) as total_tokens,
 80→      sum(input_tokens) as input_tokens,
 81→      sum(output_tokens) as output_tokens
 82→    FROM rudel.session_analytics
 83→    WHERE ${dateFilter}
 84→      AND organization_id = '${org}'
 85→      AND model_used != ''
 86→      AND model_used != 'unknown'
 87→    GROUP BY date, model
 88→    ORDER BY date ASC, total_tokens DESC
 89→  `;
 90→
 91→	return queryClickhouse<ModelTokensTrendData>(query);
 92→}
 93→
 94→/**
 95→ * Get detailed usage trend data aggregated by day
 96→ */
 97→export async function getUsageTrendDetailed(
 98→	orgId: string,
 99→	days = 30,
100→): Promise<UsageTrendData[]> {
101→	const org = escapeString(orgId);
102→	const dateFilter = buildDateFilter(days);
103→
104→	const query = `
105→    SELECT
106→      toDate(session_date) as date,
107→      count() as sessions,
108→      uniq(user_id) as active_users,
109→      round(sum(actual_duration_min) / 60, 2) as total_hours,
110→      sum(total_tokens) as total_tokens
111→    FROM rudel.session_analytics
112→    WHERE ${dateFilter}
113→      AND organization_id = '${org}'
114→    GROUP BY date
115→    ORDER BY date ASC
116→  `;
117→
118→	return queryClickhouse<UsageTrendData>(query);
119→}
120→
121→/**
122→ * Generate rule-based insights from current data
123→ */
124→export async function getOverviewInsights(
125→	orgId: string,
126→	days = 7,
127→): Promise<Insight[]> {
128→	const org = escapeString(orgId);
129→	const insights: Insight[] = [];
130→
131→	const currentPeriodQuery = `
132→    SELECT
133→      count() as total_sessions,
134→      uniq(user_id) as total_users,
135→      round(avg(actual_duration_min), 2) as avg_duration_min
136→    FROM rudel.session_analytics
137→    WHERE ${buildDateFilter(days)}
138→      AND organization_id = '${org}'
139→  `;
140→
141→	const previousDays = Number(days) * 2;
142→	const previousPeriodQuery = `
143→    SELECT
144→      count() as total_sessions,
145→      uniq(user_id) as total_users,
146→      round(avg(actual_duration_min), 2) as avg_duration_min
147→    FROM rudel.session_analytics
148→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
149→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
150→      AND organization_id = '${org}'
151→  `;
152→
153→	interface PeriodStats {
154→		total_sessions: number;
155→		total_users: number;
156→		avg_duration_min: number;
157→	}
158→
159→	const [currentData, previousData] = await Promise.all([
160→		queryClickhouse<PeriodStats>(currentPeriodQuery),
161→		queryClickhouse<PeriodStats>(previousPeriodQuery),
162→	]);
163→
164→	const current = currentData[0];
165→	const previous = previousData[0] || { total_sessions: 0 };
166→
167→	// Insight 1: Session trend analysis
168→	if (current && previous) {
169→		const sessionChange =
170→			previous.total_sessions > 0
171→				? ((current.total_sessions - previous.total_sessions) /
172→						previous.total_sessions) *
173→					100
174→				: 0;
175→
176→		if (Math.abs(sessionChange) >= 10) {
